before_code:
module counter_4bit(
  input clk,
  input reset,
  input enable,
  output [3:0] count
);
  reg [3:0] counter;

  always @(posedge clk) begin
    if (reset) counter <= 4'b0;
    else if (enable) counter <= counter + 1;
  end
  assign count = counter;
endmodule

module top_counter(
  input clk, rst,
  output [3:0] cnt
);
  counter_4bit c1(.clk(clk), .reset(rst), .enable(1'b1), .count(cnt));
endmodule

after_code:
module counter_4bit(
  input clk,
  input reset,
  output enable,
  output [3:0] count
);
  reg [3:0] counter;

  always @(posedge clk) begin
    if (reset) counter <= 4'b0;
    else counter <= counter + 1;
  end
  assign count = counter;
endmodule

module top_counter(
  input clk, rst,
  output [3:0] cnt
);
  counter_4bit c1(.clk(clk), .reset(rst), .count(cnt));
endmodule
